create.perform:
const exit = world.getEntity('exit:gate:north');
const turnstile = world.getEntity('item:stuck-turnstile');
const lever = world.getEntity('item:rusty-lever');
exit.properties.locked = false;
turnstile.description = "The brass turnstile is now functional, thanks to the rusty lever you've jammed into the socket. It rotates with a satisfyingly heavy click.";
lever.location = 'item:stuck-turnstile';
lever.tags = ['fixed'];
return "With a bit of force, you slide the rusty lever into the turnstile's socket. It fits perfectly. You give it a push, and the mechanism groans before clicking into its first rotation. The way north is clear.";

